mapper.sql:
WHERE l.active = true

    AND (l.title LIKE CONCAT('%',#{keyword},'%') OR l.description LIKE CONCAT('%',#{keyword},'%'))


    AND l.category = #{category}


    AND l.price >= #{minPrice}


    AND l.price <= #{maxPrice}


    AND l.location LIKE CONCAT('%',#{location},'%')


    AND l.theme = #{theme}


    AND l.transport_mode = #{transportMode}


    AND l.rating >= #{minRating}


    AND EXISTS (SELECT 1 FROM time_slots ts
        WHERE ts.listing_id = l.id
        AND ts.slot_date = #{availableDate}
        AND ts.booked_count < ts.capacity)

mapper.update:
UPDATE listings SET title=#{title}, description=#{description}, category=#{category},
    price=#{price}, duration_minutes=#{durationMinutes}, location=#{location},
    max_concurrent=#{maxConcurrent}, active=#{active}, theme=#{theme}, transport_mode=#{transportMode}
WHERE id = #{id}
